{
  "schema": "criterion_assessment.v1-microtest",
  "criteria": [
    {
      "id": "I1_PROMPT_TECHNIQUE",
      "status": "not_met",
      "evidence": [
        {"source": "T", "quote": "Training language models to follow instructions with human feedback"},
        {"source": "S5", "quote": "Starting with a set of labeler-written prompts and prompts submitted through the OpenAI API, we collect a dataset of labeler demonstrations of the desired model behavior, which we use to fine-tune GPT-3 using supervised learning."}
      ],
      "reason": "The paper describes fine-tuning with human feedback, not a concrete prompt-engineering operation. The prompts are used as training data, not as a technique for constructing or structuring prompts at inference time."
    },
    {
      "id": "I2_REPRODUCIBLE",
      "status": "not_met",
      "evidence": [
        {"source": "S5", "quote": "Starting with a set of labeler-written prompts and prompts submitted through the OpenAI API, we collect a dataset of labeler demonstrations of the desired model behavior, which we use to fine-tune GPT-3 using supervised learning."}
      ],
      "reason": "No identifiable prompt structure, instruction, sequence, or transferable method is described; the focus is on the training process and data collection, not a reproducible prompt technique."
    },
    {
      "id": "I3_LLM_TARGET",
      "status": "met",
      "evidence": [
        {"source": "T", "quote": "Training language models to follow instructions with human feedback"},
        {"source": "S5", "quote": "fine-tune GPT-3 using supervised learning"}
      ],
      "reason": "The technique targets large language models (GPT-3)."
    },
    {
      "id": "I4_PRACTITIONER",
      "status": "not_met",
      "evidence": [
        {"source": "S5", "quote": "fine-tune GPT-3 using supervised learning"},
        {"source": "S6", "quote": "further fine-tune this supervised model using reinforcement learning from human feedback"}
      ],
      "reason": "The approach requires fine-tuning model weights, which is not applicable by a practitioner through prompts, instructions, or inference-time orchestration alone."
    },
    {
      "id": "E1_NO_ACTIONABLE_TECHNIQUE",
      "status": "met",
      "evidence": [
        {"source": "S5", "quote": "fine-tune GPT-3 using supervised learning"}
      ],
      "reason": "The article does not propose or describe an actionable prompt technique; it focuses on model training."
    },
    {
      "id": "E2_MODEL_TRAINING_ONLY",
      "status": "met",
      "evidence": [
        {"source": "S5", "quote": "fine-tune GPT-3 using supervised learning"},
        {"source": "S6", "quote": "further fine-tune this supervised model using reinforcement learning from human feedback"}
      ],
      "reason": "The article is solely about model training and fine-tuning, without a practitioner-usable prompting component."
    },
    {
      "id": "E3_BENCHMARK_ONLY",
      "status": "not_met",
      "evidence": [
        {"source": "S8", "quote": "In human evaluations on our prompt distribution, outputs from the 1.3B parameter InstructGPT model are preferred to outputs from the 175B GPT-3"}
      ],
      "reason": "The article includes evaluations but is not solely a benchmark; it presents a training method. However, it does not provide a transferable prompt method, so it is excluded by other criteria."
    },
    {
      "id": "E4_APPLICATION_WITHOUT_PROMPT_DETAIL",
      "status": "not_met",
      "evidence": [
        {"source": "T", "quote": "Training language models to follow instructions with human feedback"}
      ],
      "reason": "The article is not a domain application of an LLM; it is a training method paper. The exclusion does not apply."
    },
    {
      "id": "E5_NON_PRIMARY_WITHOUT_ISOLABLE_TECHNIQUE",
      "status": "not_met",
      "evidence": [],
      "reason": "The article is a primary research paper, not an opinion, editorial, or survey. The exclusion does not apply."
    }
  ]
